#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#define MAX_N 300000
#define MAX_Q 20

// Structure to represent a meeting
typedef struct {
    int start;
    int end;
} Meeting;

// Comparison function for sorting meetings based on end times
int compareMeetings(const void *a, const void *b) {
    Meeting *m1 = (Meeting *)a;
    Meeting *m2 = (Meeting *)b;
    return m1->end - m2->end;
}

int main() {
    int N, Q;
    scanf("%d", &N);
    Meeting meetings[N];
    for (int i = 0; i < N; i++) {
        scanf("%d %d", &meetings[i].start, &meetings[i].end);
    }
    scanf("%d", &Q);
    long long K;
    for (int i = 0; i < Q; i++) {
        scanf("%lld", &K);
        // Sort the meetings based on end times
        qsort(meetings, N, sizeof(Meeting), compareMeetings);
        int maxIntersection = 0;
        long long credibility = K;
        for (int j = 0; j < N; j++) {
            // Calculate the maximum possible intersection
            int intersection = meetings[j].end - meetings[0].start;
            if (intersection > maxIntersection) {
                maxIntersection = intersection;
            }
            // Adjust the start time of the meeting to maximize the intersection
            if (credibility >= meetings[j].start - meetings[0].start) {
                credibility -= meetings[j].start - meetings[0].start;
                meetings[j].start = meetings[0].start;
            }
        }
        printf("%d\n", maxIntersection);
    }
    return 0;
}

