import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        Meeting[] meetings = new Meeting[N];
        for (int i = 0; i < N; i++) {
            meetings[i] = new Meeting(scanner.nextInt(), scanner.nextInt());
        }
        int Q = scanner.nextInt();
        long K;
        for (int i = 0; i < Q; i++) {
            K = scanner.nextLong();
            // Sort the meetings based on end times
            Arrays.sort(meetings);
            int maxIntersection = 0;
            long credibility = K;
            for (int j = 0; j < N; j++) {
                // Calculate the maximum possible intersection
                int intersection = meetings[j].end - meetings[0].start;
                if (intersection > maxIntersection) {
                    maxIntersection = intersection;
                }
                // Adjust the start time of the meeting to maximize the intersection
                if (credibility >= meetings[j].start - meetings[0].start) {
                    credibility -= meetings[j].start - meetings[0].start;
                    meetings[j].start = meetings[0].start;
                }
            }
            System.out.println(maxIntersection);
        }
    }
}

class Meeting implements Comparable<Meeting> {
    int start;
    int end;
    public Meeting(int start, int end) {
        this.start = start;
        this.end = end;
    }
    @Override
    public int compareTo(Meeting o) {
        return this.end - o.end;
    }
}

